#include "kernel_operator.h"
#include "ca6k_03803_custom_tiling.h"

class KernelCa6k03803Custom {
public:
    __aicore__ inline KernelCa6k03803Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR weight, GM_ADDR y,
                                uint32_t N, uint32_t C_in, uint32_t C_out,
                                uint32_t H_in, uint32_t W_in,
                                uint32_t H_out, uint32_t W_out,
                                uint32_t K_h, uint32_t K_w,
                                uint32_t stride, uint32_t padding,
                                uint32_t output_padding,
                                uint32_t dilation_h, uint32_t dilation_w)
    {
        N_ = N; C_in_ = C_in; C_out_ = C_out;
        H_in_ = H_in; W_in_ = W_in;
        H_out_ = H_out; W_out_ = W_out;
        K_h_ = K_h; K_w_ = K_w;
        stride_ = stride; padding_ = padding;
        output_padding_ = output_padding;
        dilation_h_ = dilation_h; dilation_w_ = dilation_w;

        xGm_.SetGlobalBuffer((__gm__ float*)x);
        wGm_.SetGlobalBuffer((__gm__ float*)weight);
        yGm_.SetGlobalBuffer((__gm__ float*)y);
    }

    __aicore__ inline void Process()
    {
        if (N_ == 0 || C_out_ == 0 || H_out_ == 0 || W_out_ == 0) return;

        for (uint32_t n = 0; n < N_; n++) {
            for (uint32_t c_out = 0; c_out < C_out_; c_out++) {
                for (uint32_t h_out = 0; h_out < H_out_; h_out++) {
                    for (uint32_t w_out = 0; w_out < W_out_; w_out++) {
                        float sum = 0.0f;
                        for (uint32_t ic = 0; ic < C_in_; ic++) {
                            for (uint32_t kh = 0; kh < K_h_; kh++) {
                                // Compute input height index
                                int32_t diff_h = static_cast<int32_t>(h_out) +
                                    static_cast<int32_t>(padding_) -
                                    static_cast<int32_t>(dilation_h_ * kh);
                                if (diff_h < 0) continue;
                                if (diff_h % static_cast<int32_t>(stride_) != 0) continue;
                                uint32_t h_in = static_cast<uint32_t>(diff_h / stride_);
                                if (h_in >= H_in_) continue;

                                for (uint32_t kw = 0; kw < K_w_; kw++) {
                                    int32_t diff_w = static_cast<int32_t>(w_out) +
                                        static_cast<int32_t>(padding_) -
                                        static_cast<int32_t>(dilation_w_ * kw);
                                    if (diff_w < 0) continue;
                                    if (diff_w % static_cast<int32_t>(stride_) != 0) continue;
                                    uint32_t w_in = static_cast<uint32_t>(diff_w / stride_);
                                    if (w_in >= W_in_) continue;

                                    uint32_t xIdx = ((n * C_in_ + ic) * H_in_ + h_in) * W_in_ + w_in;
                                    uint32_t wIdx = ((ic * C_out_ + c_out) * K_h_ + kh) * K_w_ + kw;
                                    sum += xGm_.GetValue(xIdx) * wGm_.GetValue(wIdx);
                                }
                            }
                        }
                        uint32_t yIdx = ((n * C_out_ + c_out) * H_out_ + h_out) * W_out_ + w_out;
                        yGm_.SetValue(yIdx, sum);
                    }
                }
            }
        }
    }

private:
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_, C_in_, C_out_, H_in_, W_in_, H_out_, W_out_;
    uint32_t K_h_, K_w_, stride_, padding_, output_padding_;
    uint32_t dilation_h_, dilation_w_;
};

extern "C" __global__ __aicore__ void ca6k_03803_custom(GM_ADDR x, GM_ADDR weight, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(td, tiling);
    KernelCa6k03803Custom op;
    op.Init(x, weight, y,
            td.N, td.C_in, td.C_out, td.H_in, td.W_in,
            td.H_out, td.W_out, td.K_h, td.K_w,
            td.stride, td.padding, td.output_padding,
            td.dilation_h, td.dilation_w);
    op.Process();
}
